INSERT INTO "public"."sources" ("id", "title", "source_url", "metadata", "type", "last_synced_at", "created_at", "content") VALUES
	('088420b3-f868-4edd-9d46-924d8b09729d', 'Privacy', 'https://ind.nl/en/privacy', '{"category": "privacy", "elements": [{"text": "Privacy", "type": "Title"}, {"text": "The Immigration and Naturalisation Service (IND) assesses all residence permit applications from the people who want to live, work or study in the Netherlands. The IND also assesses applications from the people who want to become Dutch. For this purpose, the IND processes a lot of personal data of customers and employees.", "type": "NarrativeText"}, {"text": "The IND believes that privacy is very important. That is why we process your data with great care and attention. In this Privacy Statement, you can read which data the IND collects and why. We also explain who we share your information with and what rights you have.", "type": "NarrativeText"}, {"text": "To keep the information clear, each topic is subdivided into two layers of information. First you read the most important information. Do you want to know more? Then click on the \"more information\" link.", "type": "NarrativeText"}, {"text": "You can also download our Privacy Statement:", "type": "NarrativeText"}, {"text": "privacystatement ind.pdf (PDF, 399.29 KB)", "type": "UncategorizedText"}, {"text": "Or download our Privacy Statement for Job Applicants (in Dutch only):", "type": "UncategorizedText"}, {"text": "20240612 IND Privacyverklaring sollicitant.pdf (PDF, 212.65 KB)", "type": "UncategorizedText"}, {"text": "Show details Hide details", "type": "NarrativeText"}, {"text": "More information", "type": "Title"}, {"text": "​The IND implements the aliens policy in the Netherlands. This means that the IND assesses all residence permit applications from people who want to live in the Netherlands or who want to become Dutch. This may involve refugees who are not safe in their own country and therefore apply for asylum here. This may also be people who want to work, study or form a family with someone who already lives here. In addition, the IND handles naturalization requests from the people who have been living here for so long that they feel Dutch and therefore want to apply for Dutch nationality. The IND assesses each application separately against the rules of the immigration policy. That means that we listen to the story of every applicant carefully so that every decision we take does justice to everyone''s personal situation.", "type": "NarrativeText"}, {"text": "As an implementing organisation, the IND is part of the Ministry of Asylum and Migration (residence permits) and the Ministry of Justice and Security (becoming a Dutch citizen). As a member of the government, the Minister of Asylum and Migration and the State Secretary for Justice and Security are responsible for the work of the IND. The IND has no influence on the immigration policy, which is determined via the Second and First Chamber. In addition, rules stem from (international) treaties such as the Refugee Convention and from EU legislation.", "type": "NarrativeText"}, {"text": "The IND has operating offices at various locations in the Netherlands. The main office is located at Rijnstraat 8, 2515 XP in The Hague. Next to that we distinguish 4 counters, 10 expat centres, 5 application centres and 7 offices. For example, at the counters customers can pick up a residence document or, if necessary, have biometrics (such as fingerprints) collected. The expat centres help expats when they arrive in the Netherlands. Here, expats and graduate foreign students can submit an application, have biometrics done if necessary and collect a residence document. Asylum seekers report to an application centre to apply for asylum. Finally, the offices can only be visited by appointment with an IND employee.", "type": "NarrativeText"}, {"text": "What personal information does the IND collect from you?", "type": "Title"}, {"text": "The IND processes personal data of the people who apply for a residence permit in the Netherlands or the people who apply to become Dutch nationals. We also process personal data from sponsors, family members, interpreters, agents, employees of the IND and employees of other organisations. The IND receives the personal data from these people personally or from other persons or organisations involved.", "type": "NarrativeText"}, {"text": "The IND processes general personal data. For example, name, contact information, nationality and passport number, date and place of birth and marital status, and also special personal data if it is necessary for the work of the IND, for example, racial or ethnic origin, political views and beliefs, and also genetic and biometric data, sexual orientation and information about criminal cases or a criminal record. For a comprehensive overview, see ‘more information’.", "type": "NarrativeText"}, {"text": "The IND obtains personal data in various ways:", "type": "NarrativeText"}, {"text": "The applicant provides the personal data relating to him or her in connection with the submitted application, personally or possibly through an authorised representative.", "type": "ListItem"}, {"text": "The sponsor of the person who wants to stay in the Netherlands provides the personal data about him or her.", "type": "ListItem"}, {"text": "The applicant provides personal data of third parties, such as family members.", "type": "ListItem"}, {"text": "The personal data come from other government departments and authorities.", "type": "ListItem"}, {"text": "Show details Hide details", "type": "NarrativeText"}, {"text": "More information", "type": "Title"}, {"text": "The IND collects the following personal data:", "type": "NarrativeText"}, {"text": "General personal data", "type": "Title"}, {"text": "Name", "type": "ListItem"}, {"text": "Date of birth/ age", "type": "ListItem"}, {"text": "Gender", "type": "ListItem"}, {"text": "Nationality", "type": "ListItem"}, {"text": "Country where the foreign national comes from", "type": "ListItem"}, {"text": "Country and place of birth", "type": "ListItem"}, {"text": "Marital status (for example: single, cohabiting, married)", "type": "ListItem"}, {"text": "Client-client relationships (such as: spouse/partner of, child of, parent of …)", "type": "ListItem"}, {"text": "V-number", "type": "ListItem"}, {"text": "A-number", "type": "ListItem"}, {"text": "Address", "type": "ListItem"}, {"text": "Address abroad", "type": "ListItem"}, {"text": "E-mail address", "type": "ListItem"}, {"text": "Telephone number", "type": "ListItem"}, {"text": "Copy of the passport/ID", "type": "ListItem"}, {"text": "Date on which you were registered with the IND", "type": "ListItem"}, {"text": "Date on which you were registered in the BRP", "type": "ListItem"}, {"text": "Residence status, residence permit type and validity period of the residence permit", "type": "ListItem"}, {"text": "Application or applications for the residence permit (asylum or regular) and all documents submitted with the application. These are also original documents", "type": "ListItem"}, {"text": "Date on which you became a Dutch national", "type": "ListItem"}, {"text": "Personal data in documents from your file. For example, reports of hearings and letters", "type": "ListItem"}, {"text": "Financial data", "type": "ListItem"}, {"text": "Bank account number", "type": "ListItem"}, {"text": "Notes of a contact", "type": "ListItem"}, {"text": "Notifications received", "type": "ListItem"}, {"text": "The date on which you left the Netherlands", "type": "ListItem"}, {"text": "Country where you went to", "type": "ListItem"}, {"text": "Whether the government may expel you from the Netherlands", "type": "ListItem"}, {"text": "Special personal data", "type": "Title"}, {"text": "Race or ethnic origin", "type": "ListItem"}, {"text": "Political views", "type": "ListItem"}, {"text": "Religion or philosophy of life", "type": "ListItem"}, {"text": "Whether you are a member of a trade union", "type": "ListItem"}, {"text": "Biometric data (such as fingerprints, face scan)", "type": "ListItem"}, {"text": "Information about your health", "type": "ListItem"}, {"text": "Sexual behaviour / orientation", "type": "ListItem"}, {"text": "Other information", "type": "Title"}, {"text": "Citizen service number or another identification number stated in the law", "type": "ListItem"}, {"text": "Criminal convictions and offenses or security measures", "type": "ListItem"}, {"text": "The IND cooperates, among others, with the following government services and social organisations:", "type": "NarrativeText"}, {"text": "Repatriation and Departure Service (DTenV);", "type": "ListItem"}, {"text": "Central Agency for the Reception of Asylum Seekers (COA);", "type": "ListItem"}, {"text": "Royal Netherlands Marechaussee (KMar);", "type": "ListItem"}, {"text": "International Organisation for Migration (IOM);", "type": "ListItem"}, {"text": "Municipalities;", "type": "ListItem"}, {"text": "Stichting NIDOS;", "type": "ListItem"}, {"text": "Ministry of Foreign Affairs;", "type": "ListItem"}, {"text": "Inspection services, such as the Social Affairs & Employment Inspectorate;", "type": "ListItem"}, {"text": "DUO;", "type": "ListItem"}, {"text": "Tax authorities;", "type": "ListItem"}, {"text": "European sister services and NGOs;", "type": "ListItem"}, {"text": "Judicial information service;", "type": "ListItem"}, {"text": "Custodial Institutions Agency (DJI);", "type": "ListItem"}, {"text": "Public Prosecution Service (OM);", "type": "ListItem"}, {"text": "National Police (NP);", "type": "ListItem"}, {"text": "Employee Insurance Agency (UWV);", "type": "ListItem"}, {"text": "BKWI (Suwinet);", "type": "ListItem"}, {"text": "Dutch Council for Refugees (VWN).", "type": "ListItem"}, {"text": "Full overview of the organisations with which the IND cooperates:", "type": "UncategorizedText"}, {"text": "AVG stakeholders IND.pdf (PDF, 32.19 KB)", "type": "UncategorizedText"}, {"text": "Why does the IND process your personal data?", "type": "Title"}, {"text": "The IND needs your personal data to implement the Policy on Foreign nationals. This policy stems from the Aliens Act 2000 and rules and regulations that go with it, as well as from the Dutch Nationality Act. In addition, there are rules based on international treaties.", "type": "NarrativeText"}, {"text": "The IND manages the administration of foreign nationals. After identification, the personal data of the foreign nationals are registered herein.", "type": "NarrativeText"}, {"text": "Show details Hide details", "type": "NarrativeText"}, {"text": "More information", "type": "Title"}, {"text": "Privacy legislation requires that we only process personal data for clearly defined purposes. The purposes for which we process your data are described in article 107 of the Aliens Act 2000.", "type": "NarrativeText"}, {"text": "In summary, the IND collects the personal data for, among other things:", "type": "NarrativeText"}, {"text": "Implementing the Aliens Act 2000, the Dutch Nationality Act and other legal regulations;", "type": "ListItem"}, {"text": "Verification, checking and referral and making this data available;", "type": "ListItem"}, {"text": "Evaluation of aliens policy and policy of the IND;", "type": "ListItem"}, {"text": "The purpose of processing the special categories of personal data is described in article 107a of the Aliens Act 2000.", "type": "ListItem"}, {"text": "The special categories of personal data are processed by us to the extent that this data are necessary for:", "type": "NarrativeText"}, {"text": "issuing visas;", "type": "ListItem"}, {"text": "border control;", "type": "ListItem"}, {"text": "admission, residence and expulsion of aliens;", "type": "ListItem"}, {"text": "supervision of foreign nationals on the basis of the Aliens Act 2000 or the Schengen Borders Code;", "type": "ListItem"}, {"text": "In Article 7.1a of the Aliens Regulations 2000 states when it is necessary to process the special personal data.", "type": "ListItem"}, {"text": "Whom does the IND provide our personal data to?", "type": "Title"}, {"text": "According to the Aliens Act 2000, the IND may or must provide other government organisations with information to perform their duties. For this purpose, such organisation requests (request) or demands information (claim).", "type": "NarrativeText"}, {"text": "The IND assesses whether it is necessary to provide your personal data and whether it does not harm your personal life. The IND checks why the organisation wants to get the data and whether it can do with less or no personal data.", "type": "NarrativeText"}, {"text": "Show details Hide details", "type": "NarrativeText"}, {"text": "More information", "type": "Title"}, {"text": "The IND shares personal data with other organisations in the immigration chain. These are the Repatriation and Departure Service (DTenV), the Central Agency for the Reception of Asylum Seekers (COA), the Royal Netherlands Marechaussee, the National Police, the Ministry of Foreign Affairs, the Custodial Institutions Service (DJI), and the International Organisation for Migration (IOM). All these organisations have their own role in supporting foreign nationals on the way to the Netherlands, in the Netherlands and on the way out of the Netherlands. In addition, the IND shares data with other Dutch government organisations. For example, the UWV or the Public Prosecution Service (OM).", "type": "NarrativeText"}, {"text": "Sometimes the IND shares data with organisations that are not government institutions. They are often associations and foundations. For example, Dutch Council for Refugees (VWN). These organisations only receive personal data if this is necessary to implement the immigration policy.", "type": "NarrativeText"}, {"text": "Research", "type": "Title"}, {"text": "The IND’s Research & Analysis (In Dutch: Onderzoek & Analyse or O&A) department conducts research. These studies are either confidential or public. Additionally, O&A assesses applications from external parties requesting IND data for research purposes. For example, researchers request interviews with IND staff, but also figures, access to case file information and internal documents. If the application is approved, O&A arranges access to the requested information under strict conditions. For instance, external researchers sign a non-disclosure agreement. This states that they will not include any data that can be traced back to an individual in the public research report. Written agreements are also made for each study regarding the data to be provided, the manner in which the information is given and the review, including fact-checking, that the IND will carry out on the publication. Research involving the IND can be divided into the following three categories:", "type": "NarrativeText"}, {"text": "research which the IND is legally obliged to cooperate with;", "type": "ListItem"}, {"text": "research by external partieswho are granted access to data within the IND. This often concerns requests from universities, students and civil society organisations;", "type": "ListItem"}, {"text": "research conducted by IND departments themselves.", "type": "ListItem"}, {"text": "Show details Hide details", "type": "NarrativeText"}, {"text": "More information", "type": "Title"}, {"text": "Mandatory research", "type": "Title"}, {"text": "The IND cooperates with research by the following institutions:", "type": "NarrativeText"}, {"text": "the Research and Data Centre (wodc.nl: in Dutch only);", "type": "ListItem"}, {"text": "the Advisory Council on Migration (adviesraadmigratie.nl: in Dutch only);", "type": "ListItem"}, {"text": "the Inspectorate of Justice and Security (inspectie-jenv.nl: in Dutch only);", "type": "ListItem"}, {"text": "the Netherlands Court of Audit (rekenkamer.nl: in Dutch only);", "type": "ListItem"}, {"text": "the United Nations High Commissioner for Refugees (unhcr.org/nl).", "type": "ListItem"}, {"text": "Non-mandatory research", "type": "Title"}, {"text": "In the category of non-mandatory academic research, the IND facilitates Dutch and foreign universities. This may involve research by academic staff, but also research by students for their master''s dissertations. Research by civil society organisations can also be facilitated.", "type": "NarrativeText"}, {"text": "Personal data are only processed when necessary for the research", "type": "Title"}, {"text": "In general, personal data are processed in research only when strictly necessary for conducting the research. Research findings may be published in scientific publications and/or on research institutes’ websites. The publications contain the anonymised and/or combined results of the research. The privacy of research participants is safeguarded in privacy regulations. Researchers sign a non-disclosure agreement.", "type": "NarrativeText"}, {"text": "More information about IND research", "type": "Title"}, {"text": "For more information about research within and by the IND, contact the Research Support Cluster of the Research & Analysis department at INDOA@ind.nl.", "type": "NarrativeText"}, {"text": "​Does the IND share your personal data with other countries?", "type": "Title"}, {"text": "In certain situations, the IND passes on personal data to other countries or (international) organisations.", "type": "NarrativeText"}, {"text": "Sharing your personal data with countries within the EEA", "type": "Title"}, {"text": "The AVG rules also apply in the countries within the European Economic Area (EEA). These are all countries of the European Union plus Norway, Iceland and Liechtenstein. These countries protect your personal data as well as the Netherlands.", "type": "NarrativeText"}, {"text": "Sharing your personal data with countries or organisations outside the EEA", "type": "Title"}, {"text": "In such case, the IND takes measures to protect your personal data. For example, by providing data to the countries for which the European Commission has taken an adequacy decision. The IND also exchanges personal data with embassies of countries where foreign nationals come from. This happens for the reasons that are important to everyone (Article 49, paragraph 1, sub d., GDPR).", "type": "NarrativeText"}, {"text": "Show details Hide details", "type": "NarrativeText"}, {"text": "More information", "type": "Title"}, {"text": "Adequacy decision", "type": "Title"}, {"text": "According to the law, the IND may transfer personal data on the basis of an ''adequacy decision''. An adequacy decision is the decision of the European Commission (EC) in which the EC has determined that this country protects data at the AVG level in its own laws.", "type": "NarrativeText"}, {"text": "The adequacy decision can apply to an entire country or for one or more sectors or regions in that country. Is there an adequacy decision in place? Then no additional measures are needed to provide personal data to this country, sector or region.", "type": "NarrativeText"}, {"text": "The EC has adopted an adequacy decision for the following countries and regions:", "type": "NarrativeText"}, {"text": "Andorra;", "type": "ListItem"}, {"text": "Argentina;", "type": "ListItem"}, {"text": "Canada (with the exception of Quebec) (see explanation below);", "type": "ListItem"}, {"text": "Isle of Man;", "type": "ListItem"}, {"text": "Faroe Islands;", "type": "ListItem"}, {"text": "Guernsey;", "type": "ListItem"}, {"text": "Israel;", "type": "ListItem"}, {"text": "Japan;", "type": "ListItem"}, {"text": "Jersey", "type": "ListItem"}, {"text": "New Zealand;", "type": "ListItem"}, {"text": "Uruguay;", "type": "ListItem"}, {"text": "United States of America (see explanation below);", "type": "ListItem"}, {"text": "Switzerland.", "type": "ListItem"}, {"text": "For Canada, the adequacy decision only applies to electronically processed data covered by the Canadian Personal Information Protection and Electronic Documents Act (PIPEDA).", "type": "NarrativeText"}, {"text": "Concerning the United States, there is no appropriate level of protection for the country as a whole. The EC has adopted EU-US Privacy Shield. Companies and institutions can receive a certificate from the Privacy Shield. Personal data may only be shared with companies and institutions with a Privacy Shield certificate. On the official website (privacyshield.gov/welcome) there is a list of all certified organisations.", "type": "NarrativeText"}, {"text": "Information about adequacy decisions on the website of the European Commission", "type": "UncategorizedText"}, {"text": "Sharing personal data with countries without adequacy decision", "type": "Title"}, {"text": "Your personal data can also be passed on to a country without the adequacy decision. This can only be done if one of the exceptions referred to in Article 49 of the GDPR is met. Article 49, paragraph 1, sub ''d'' of the GDPR allows sharing personal data if there are important reasons in the public interest. Art. 49 paragraph 4 sets the additional requirement that this public interest is recognised in a law of the European Union or a law of the Netherlands that applies to the organisation responsible for the processing of those personal data.", "type": "NarrativeText"}, {"text": "To the IND, the Aliens Act 2000 applies. It states that the IND must keep records of foreign nationals. Another law is the Regulation (EU) 2019/1240 of the European Parliament and the European Council of 20 June 2019.", "type": "NarrativeText"}, {"text": "Exchanged of data with other organisations in the Netherlands and abroad", "type": "Title"}, {"text": "The IND must also be able to share personal data with law enforcement authorities, foreign authorities and within networks of immigration liaison officers. The IND only does this if those personal details are necessary for the following purposes:", "type": "NarrativeText"}, {"text": "implementation of the Aliens Act,", "type": "ListItem"}, {"text": "prevention and tackling of irregular migration, or", "type": "ListItem"}, {"text": "prevention, investigation, detection and prosecution of migrant smuggling or human trafficking.", "type": "ListItem"}, {"text": "The AVG applies to such processing of personal data. This means that:", "type": "NarrativeText"}, {"text": "personal data must be deleted if they are no longer needed for the purpose for which they were collected or processed.", "type": "ListItem"}, {"text": "any exchange of personal data is limited to what is strictly necessary for the application of the Aliens Act and / or the Regulation.", "type": "ListItem"}, {"text": "​How does the IND protect your personal data?", "type": "Title"}, {"text": "The IND has taken measures to protect personal data and prevent misuse. All persons who can access the data must keep this information secret.", "type": "NarrativeText"}, {"text": "Show details Hide details", "type": "NarrativeText"}, {"text": "More information", "type": "Title"}, {"text": "Customers and employees trust that personal data are in good hands with the IND. Therefore, the IND protects personal data with suitable technical and organisational measures.", "type": "NarrativeText"}, {"text": "The IND has introduced the Government Information Management Baseline (BIO) for the protection of data in the systems. The technical measures that the IND has introduced to protect personal data, are in accordance with the BIO. The IND actively implements the BIO.", "type": "NarrativeText"}, {"text": "The IND has taken extra measures to protect your data at all times. Technology and processes have been adjusted. The IND also teaches its employees what the risks there are and how they should deal with them. The IND ensures that the risks are reduced and audits the measures.", "type": "NarrativeText"}, {"text": "​How long will your personal information be stored?", "type": "Title"}, {"text": "The IND does not store personal data for longer than necessary for the purpose for which the IND has collected it. The retention periods are laid down in the archive policy. How long personal data are preserved, varies per situation and also depends on the purpose of storage. This period can be a few weeks to many years.", "type": "NarrativeText"}, {"text": "Show details Hide details", "type": "NarrativeText"}, {"text": "More information", "type": "Title"}, {"text": "The Minister of Asylum and Migration (residence permits) and the Minister of Justice and Security has a duty of care (that is an administrative responsibility) to keep the archive of the IND in order and to ensure that there is access to the archive. It is stated in Article 3 of the 1995 Archive Act.", "type": "NarrativeText"}, {"text": "The Minister of Justice and Security has made selection lists. This is stated in Article 5 of the 1995 Archive Act. The selection lists state how long the IND must keep its archives and whether the IND may destroy an archive after a certain time.", "type": "NarrativeText"}, {"text": "The following selection lists are made for the IND:", "type": "NarrativeText"}, {"text": "Selelection list for the repercussions of the actions of Minister of Justice and actors involved in the field of admission of foreign aliens 1945-1993, 18 February 2002 R&B/OSA/2002/578 (Dutch Government Gazette no. 95, 23 May 2002)", "type": "ListItem"}, {"text": "Selection list for the repercussions of the actions of the Ministry of Justice in the field of Admission of Aliens from 1945, 20 November 2009, no. NA/09/3091 (Dutch Government Gazette no. 1754, 9 February 2010).", "type": "UncategorizedText"}, {"text": "BSD Actualisatie Toelating Vreemdelingen stcrnt 09 02 2010.pdf (PDF, 556.2 KB)", "type": "UncategorizedText"}, {"text": "Determination of the selection list in the field of Nationalities for the period from 1945, 17 March 2003, no. C/S/03/705 (Dutch Government Gazette no. 86, 6 May 2003)​​​​​​. ​BSD Nationaliteiten 1945 - heden).", "type": "ListItem"}, {"text": "These selection lists are published in the Dutch Government Gazette.", "type": "NarrativeText"}, {"text": "All retention periods of the IND:", "type": "UncategorizedText"}, {"text": "AVG Bewaartermijnenlijst IND.pdf (PDF, 198.24 KB)", "type": "UncategorizedText"}, {"text": "Basis for the retention periods:", "type": "UncategorizedText"}, {"text": "AVG Grondslagen bewaartermijnenlijst IND.pdf (PDF, 162.5 KB)", "type": "UncategorizedText"}, {"text": "Retention periods", "type": "Title"}, {"text": "The archives of foreign nationals who remain for indefinite period are preserved forever.", "type": "NarrativeText"}, {"text": "From 1990, the archives of foreign nationals with a residence permit for a limited period are preserved for 15 years. The retention period starts on the departure date.", "type": "NarrativeText"}, {"text": "The archives of foreign nationals who acquire Dutch nationality are preserved forever. These archives are an important source of information for immigrants and their descendants about their arrival in the Netherlands.", "type": "NarrativeText"}, {"text": "These retention periods have been determined after advice from the Dutch Council for Culture. The selection list has been formally determined by the Minister of Education, Culture and Science and the Minister of Justice.", "type": "NarrativeText"}, {"text": "Managing director of the IND gives shape to the archive policy form", "type": "Title"}, {"text": "The managing director of the IND determines the archive policy on behalf of the Minister of Justice. This is stated in Article 14 of the Archive Decree and Article 3 under 5 of the Justice and Safety archive management rules. When drawing up a selection list, the managing director must involve the State archivist and an external expert. The final retention period is determined by considering a number of interests. Privacy is one of these interests.", "type": "NarrativeText"}, {"text": "Retrieval of file document from the period before 1986", "type": "Title"}, {"text": "The entire archive of t