See also

Your Europe'),
	('2fe1a9bb-a22c-42a4-9564-518d67332bb3', 'Permanent residency for Union citizens and their family', 'https://ind.nl/en/residence-permits/eu-eea-or-swiss-citizens/permanent-residency-for-union-citizens-and-their-family', '{"category": "residence-permits/eu-eea-or-swiss-citizens", "elements": [{"text": "Permanent residency for Union citizens and their family", "type": "Title"}, {"text": "Last update: 11 November 2025", "type": "UncategorizedText"}, {"text": "You or your family member want to apply for permanent residency for Union citizens. Find out what the requirements are and how you can apply for the residence document.", "type": "NarrativeText"}, {"text": "Requirements", "type": "UncategorizedText"}, {"text": "Process and costs", "type": "UncategorizedText"}, {"text": "Application forms", "type": "UncategorizedText"}, {"text": "The residence document", "type": "ListItem"}, {"text": "See also", "type": "ListItem"}, {"text": "Requirements", "type": "Title"}, {"text": "These requirements apply to the residence permit for Union citizens.", "type": "NarrativeText"}, {"text": "You have the nationality of a country of the European Union (EU), the European Economic Area (EEA) or Switzerland. Or you have another nationality, but are a family member of a Union citizen. Or you are the family member or ex-partner of a Dutch national who comes under EU law. These family members come under EU law.", "type": "ListItem"}, {"text": "Married, unmarried or registered partner or ex-partner.", "type": "ListItem"}, {"text": "Parent or parent-in-law, grandparent, child, grandchild, or great-grandchild.", "type": "ListItem"}, {"text": "Another family member, for example an uncle, aunt or cousin. In this case, one of these situations must apply to this family member.", "type": "ListItem"}, {"text": "The family member depends on you financially. Without money from you, your family member cannot pay for their basic needs. Basic needs are, for example, rent, food and drink. The family member is receiving money from you regularly, for example every month.", "type": "ListItem"}, {"text": "The family member needs care from you for serious health issues.", "type": "ListItem"}, {"text": "The family member depends on you and was already living with you in the country of origin.", "type": "ListItem"}, {"text": "You have a valid passport or other travel document.", "type": "ListItem"}, {"text": "You are registered in the Personal Records Database (in Dutch: Basisregistratie Personen or BRP) of the town hall in the area where you live.", "type": "ListItem"}, {"text": "You have been living in the Netherlands continuously for 5 or more years at the time of application. During that time, you worked or you had enough money to live on. As a family member or ex-partner, you have met the requirements for residency Union citizens for 5 years.", "type": "ListItem"}, {"text": "Who cannot apply for this residence permit?", "type": "Title"}, {"text": "You cannot apply for permanent residency if you have a residence permit for residency with a minor Dutch Child (Chavez). You can however apply for a permanent residence permit, or for a residence permit for long-term EU residents. Go to the page Permanent residence permit for more information about both residence permits.", "type": "NarrativeText"}, {"text": "Are you a United Kingdom (UK) citizen? Or are you the family member of a UK national and you do not have EU, EEA or Swiss nationality? Then visit our web page Permanent residency Brexit.", "type": "NarrativeText"}, {"text": "Applying for permanent residency after less than 5 years of residency", "type": "Title"}, {"text": "Sometimes you can apply for permanent residency if you have been living in the Netherlands for less than 5 years. This is the case in these situations.", "type": "NarrativeText"}, {"text": "Show details Hide details", "type": "NarrativeText"}, {"text": "You retired at pension age or earlier", "type": "Title"}, {"text": "You have been living in the Ne